let domainFilter = dynamic([{Domain}]);
let reporterFilter = dynamic([{Reporter}]);
DMARCReports_CL
| where TimeGenerated {TimeRange}
| where '*' in (domainFilter) or Domain in (domainFilter)
| where '*' in (reporterFilter) or ReportOrgName in (reporterFilter)
| summarize arg_max(TimeGenerated, PolicyPublished_p) by Domain
| summarize Domains = count() by Policy = case(PolicyPublished_p == 'reject', 'p=reject', PolicyPublished_p == 'quarantine', 'p=quarantine', PolicyPublished_p == 'none', 'p=none', 'Unknown')

let domainFilter = dynamic([{Domain}]);
let reporterFilter = dynamic([{Reporter}]);
DMARCReports_CL
| where TimeGenerated {TimeRange}
| where '*' in (domainFilter) or Domain in (domainFilter)
| where '*' in (reporterFilter) or ReportOrgName in (reporterFilter)
| summarize Messages = sum(MessageCount) by SpfResult
| sort by Messages desc

