let domainFilter = dynamic([{Domain}]);
let reporterFilter = dynamic([{Reporter}]);
DMARCReports_CL
| where TimeGenerated {TimeRange}
| where '*' in (domainFilter) or Domain in (domainFilter)
| where '*' in (reporterFilter) or ReportOrgName in (reporterFilter)
| summarize arg_max(TimeGenerated, PolicyPublished_p, PolicyPublished_sp, PolicyPublished_pct, PolicyPublished_adkim, PolicyPublished_aspf) by Domain
| project Domain, Policy=PolicyPublished_p, SubdomainPolicy=PolicyPublished_sp, Pct=PolicyPublished_pct, DKIM_Alignment=PolicyPublished_adkim, SPF_Alignment=PolicyPublished_aspf

let domainFilter = dynamic([{Domain}]);
let reporterFilter = dynamic([{Reporter}]);
let allData = DMARCReports_CL
| where '*' in (domainFilter) or Domain in (domainFilter)
| where '*' in (reporterFilter) or ReportOrgName in (reporterFilter);
let historicalReporters = allData
| where TimeGenerated between (ago(90d) .. ago(30d))
| summarize LastSeenBefore30d = max(TimeGenerated), Messages = sum(MessageCount) by ReportOrgName;
let recentReporters = allData
| where TimeGenerated > ago(30d)
| distinct ReportOrgName;
historicalReporters
| where ReportOrgName !in (recentReporters)
| project MissingReporter = ReportOrgName, LastSeen = LastSeenBefore30d, PreviousMessages = Messages, Note = 'Previously active reporter has not sent reports in the last 30 days.'
| sort by PreviousMessages desc

let domainFilter = dynamic([{Domain}]);
let reporterFilter = dynamic([{Reporter}]);
DMARCReports_CL
| where TimeGenerated {TimeRange}
| where '*' in (domainFilter) or Domain in (domainFilter)
| where '*' in (reporterFilter) or ReportOrgName in (reporterFilter)
| summarize Reports = dcount(ReportId) by bin(TimeGenerated, 1d), ReportOrgName
| sort by TimeGenerated asc
